"use strict";(self.webpackChunkredux_box=self.webpackChunkredux_box||[]).push([[522],{3136(e,t,a){a.r(t),a.d(t,{_pageData:()=>d,default:()=>o});var s=a(641);const d=JSON.parse('{"path":"/api/moduleRegistry.html","title":"moduleRegistry","lang":"en-US","frontmatter":{"title":"moduleRegistry"},"git":{"updatedTime":1778312827000,"contributors":[{"name":"Anish Kumar","username":"","email":"anish000kumar@gmail.com","commits":1}],"changelog":[{"hash":"594d62902ab92e6dc03bcfce4fa066d20824da61","time":1778312827000,"email":"anish000kumar@gmail.com","author":"Anish Kumar","message":"coveralls upgraded and docs polish"}]},"filePathRelative":"api/moduleRegistry.md"}'),n={name:"moduleRegistry.md"},o=(0,a(6262).A)(n,[["render",function(e,t,a,d,n,o){return(0,s.uX)(),(0,s.CE)("div",null,[...t[0]||(t[0]=[(0,s.Fv)('<h1 id="moduleregistry" tabindex="-1"><a class="header-anchor" href="#moduleregistry"><span>moduleRegistry</span></a></h1><p><a name="ModuleRegistry"></a></p><h2 id="moduleregistry-1" tabindex="-1"><a class="header-anchor" href="#moduleregistry-1"><span>ModuleRegistry</span></a></h2><p><strong>Kind</strong>: global class</p><ul><li><a href="#ModuleRegistry">ModuleRegistry</a><ul><li><a href="#new_ModuleRegistry_new">new ModuleRegistry()</a></li><li><a href="#ModuleRegistry+register">.register(name, module)</a> ⇒ <code>void</code></li><li><a href="#ModuleRegistry+getName">.getName(id)</a> ⇒ <code>String</code> | <code>null</code></li></ul></li></ul><p><a name="new_ModuleRegistry_new"></a></p><h3 id="new-moduleregistry" tabindex="-1"><a class="header-anchor" href="#new-moduleregistry"><span>new ModuleRegistry()</span></a></h3><p>Internal singleton that keeps track of every module attached to the redux store and the key it was mounted under. The registry is populated by <a href="createStore">createStore</a> when it iterates the <code>modules</code> map and is consumed by <a href="createModule">createModule</a> helpers (<code>getName</code>, <code>getSelector</code>, <code>select</code>) so that modules don&#39;t have to hard-code their slice key.</p><p>You generally don&#39;t need to touch the registry yourself - it is exported mostly for advanced use cases (testing, hot module replacement, debugging).</p><p><strong>Example</strong></p><div class="language-javascript line-numbers-mode" data-highlighter="prismjs" data-ext="js"><pre><code class="language-javascript"><span class="line"><span class="token keyword">import</span> moduleRegistry <span class="token keyword">from</span> <span class="token string">&#39;redux-box/dist/moduleRegistry&#39;</span><span class="token punctuation">;</span></span>\n<span class="line"></span>\n<span class="line"><span class="token comment">// After createStore() has run, look up the slice key for a module id:</span></span>\n<span class="line"><span class="token keyword">const</span> sliceKey <span class="token operator">=</span> moduleRegistry<span class="token punctuation">.</span><span class="token function">getName</span><span class="token punctuation">(</span>userModule<span class="token punctuation">.</span>id<span class="token punctuation">)</span><span class="token punctuation">;</span></span>\n<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><a name="ModuleRegistry+register"></a></p><h3 id="moduleregistry-register-name-module-⇒-void" tabindex="-1"><a class="header-anchor" href="#moduleregistry-register-name-module-⇒-void"><span>moduleRegistry.register(name, module) ⇒ <code>void</code></span></a></h3><p>Registers a module under the key it is mounted with in the store. Called automatically by <a href="createStore">createStore</a> for every entry of the <code>modules</code> argument.</p><p><strong>Kind</strong>: instance method of <a href="#ModuleRegistry"><code>ModuleRegistry</code></a></p><table><thead><tr><th>Param</th><th>Type</th><th>Description</th></tr></thead><tbody><tr><td>name</td><td><code>String</code></td><td>The key the module is mounted under in the store.</td></tr><tr><td>module</td><td><code>Object</code></td><td>The module object returned by <a href="createModule">createModule</a>. Must have an <code>id</code>.</td></tr></tbody></table><p><a name="ModuleRegistry+getName"></a></p><h3 id="moduleregistry-getname-id-⇒-string-null" tabindex="-1"><a class="header-anchor" href="#moduleregistry-getname-id-⇒-string-null"><span>moduleRegistry.getName(id) ⇒ <code>String</code> | <code>null</code></span></a></h3><p>Returns the store key a module was mounted under, given its id.</p><p><strong>Kind</strong>: instance method of <a href="#ModuleRegistry"><code>ModuleRegistry</code></a><br><strong>Returns</strong>: <code>String</code> | <code>null</code> - The mounted slice key, or <code>null</code> if the module is not registered.</p><table><thead><tr><th>Param</th><th>Type</th><th>Description</th></tr></thead><tbody><tr><td>id</td><td><code>String</code></td><td>The unique id assigned to the module by <a href="createModule">createModule</a>.</td></tr></tbody></table>',21)])])}]])}}]);